// ============================================================
// FONTES RSS — Federações Gaúchas confirmadas
// ativo: true = será buscado a cada 6h
// ativo: false = aguardando validação
// ============================================================
const fontes = [

  // ✅ RSS CONFIRMADOS — WordPress com /feed nativo
  {
    nome: 'Federação Gaúcha de Ciclismo',
    url_rss: 'https://www.fgc.com.br/feed/',
    esporte_slug: 'ciclismo',
    ativo: true
  },
  {
    nome: 'IFBB RS (Fisiculturismo)',
    url_rss: 'https://www.ifbbrs.com.br/feed/',
    esporte_slug: 'fisiculturismo',
    ativo: true
  },
  {
    nome: 'Federação Gaúcha de Judô',
    url_rss: 'https://judors.com.br/feed/',
    esporte_slug: 'judo',
    ativo: true
  },

  // ✅ RSS de referência nacional
  {
    nome: 'GloboEsporte',
    url_rss: 'https://ge.globo.com/rss/atomfeed.xml',
    esporte_slug: 'futebol',
    ativo: true
  },

  // ⏳ SEM RSS — SPA/custom (scraping futuro via Apify)
  // FGARS (Atletismo): https://www.fgars.org/#/pages/news — SPA, sem RSS
  // Tênis Integrado: https://www.tenisintegrado.com.br — backend Java, sem RSS

  // ✅ RSS CONFIRMADOS — validados em 2026-03-16
  {
    nome: 'Federação Gaúcha de Basketball',
    url_rss: 'https://basquetegaucho.com.br/feed/',
    esporte_slug: 'basquete',
    ativo: true
  },

  // ⏳ SEM RSS — aguardando validação ou site sem feed
  {
    nome: 'Federação Gaúcha de Futebol',
    url_rss: 'https://www.fgf.com.br/feed',
    esporte_slug: 'futebol',
    ativo: false
  },
  {
    nome: 'Federação Gaúcha de Vôlei',
    url_rss: 'https://www.fgv.com.br/feed',
    esporte_slug: 'volei',
    ativo: false
  }
];

return fontes
  .filter(f => f.ativo)
  .map(f => ({ json: f }));

// Parsear XML do RSS e extrair itens
const xml = $input.item.json.data;
const fonte_nome = $('📋 Lista de Fontes RSS').item.json.nome;
const esporte_slug = $('📋 Lista de Fontes RSS').item.json.esporte_slug;

if (!xml || typeof xml !== 'string') {
  console.log(`⚠️ Sem resposta de ${fonte_nome}`);
  return [];
}

// Decodifica entidades HTML (named + numeric) — fix encoding português
const decodeEntities = (str) => {
  if (!str) return str;
  const entities = {
    '&amp;': '&', '&lt;': '<', '&gt;': '>',
    '&nbsp;': ' ', '&aacute;': 'á', '&eacute;': 'é', '&iacute;': 'í',
    '&oacute;': 'ó', '&uacute;': 'ú', '&Aacute;': 'Á', '&Eacute;': 'É',
    '&Iacute;': 'Í', '&Oacute;': 'Ó', '&Uacute;': 'Ú', '&atilde;': 'ã',
    '&otilde;': 'õ', '&Atilde;': 'Ã', '&Otilde;': 'Õ', '&ccedil;': 'ç',
    '&Ccedil;': 'Ç', '&agrave;': 'à', '&egrave;': 'è', '&acirc;': 'â',
    '&ecirc;': 'ê', '&ocirc;': 'ô', '&ucirc;': 'û', '&ndash;': '–',
    '&mdash;': '—', '&hellip;': '…', '&lsquo;': '\u2018', '&rsquo;': '\u2019',
    '&ldquo;': '\u201C', '&rdquo;': '\u201D'
  };
  return str
    .replace(/&#x([0-9a-fA-F]+);/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
    .replace(/&#([0-9]+);/g, (_, dec) => String.fromCharCode(parseInt(dec, 10)))
    .replace(/&[a-zA-Z]+;/g, (ent) => entities[ent] || ent);
};

const extract = (text, tag) => {
  const r = new RegExp(
    `<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>|<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`,
    'i'
  );
  const m = text.match(r);
  return (m ? (m[1] || m[2]) : '').trim();
};

const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
const items = [];
let match;

while ((match = itemRegex.exec(xml)) !== null) {
  const item = match[1];
  const titulo = decodeEntities(extract(item, 'title'));
  const link = extract(item, 'link') || extract(item, 'guid');
  const descricao = extract(item, 'description');

  // Extrai link: RSS padrão ou Atom (<link href="URL" />)
  const linkAtomMatch = item.match(/<link[^>]+href=["']([^"']+)["'][^>]*\/?>/i);
  const fonte_url = link || (linkAtomMatch ? linkAtomMatch[1] : null);

  const imgMatch = descricao.match(/<img[^>]+src=["']([^"']+)["']/i);
  const imagem_url = imgMatch ? imgMatch[1] : null;
  const resumo = decodeEntities(descricao.replace(/<[^>]+>/g, '').trim().substring(0, 300)) || null;

  if (titulo && fonte_url) {
    items.push({ titulo, fonte_url, fonte_nome, resumo, imagem_url, esporte_slug });
  }
}

console.log(`${fonte_nome}: ${items.length} itens encontrados`);
return items.map(i => ({ json: i }));

// Extrai conteúdo completo e melhor imagem do artigo
const html = $input.item.json.data || '';
const item = $('🔄 Um item por vez').item.json;

// Extrai og:image — múltiplos padrões de atributos
let imagem_url = item.imagem_url || null;
const ogImagePatterns = [
  /<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i,
  /<meta[^>]+content=["']([^"']+)["'][^>]+property=["']og:image["']/i,
  /<meta[^>]+name=["']twitter:image["'][^>]+content=["']([^"']+)["']/i,
  /<meta[^>]+content=["']([^"']+)["'][^>]+name=["']twitter:image["']/i,
];
for (const pattern of ogImagePatterns) {
  const m = html.match(pattern);
  if (m && m[1] && m[1].startsWith('http')) {
    imagem_url = m[1];
    break;
  }
}

// Extrai parágrafos a partir de um ponto de ancoragem no HTML
// Resolve problema de regex com divs aninhados (parava no 1º </div>)
function extractFromAnchor(htmlStr, anchorRegex) {
  const m = htmlStr.match(anchorRegex);
  if (!m) return null;
  const start = htmlStr.indexOf(m[0]);
  if (start === -1) return null;
  const chunk = htmlStr.substring(start, start + 25000);
  const paragraphs = (chunk.match(/<p[^>]*>[\s\S]*?<\/p>/gi) || [])
    .map(p => p.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim())
    .filter(p => p.length > 40);
  if (paragraphs.length === 0) return null;
  return '<p>' + paragraphs.slice(0, 40).join('</p>\n<p>') + '</p>';
}

const anchors = [
  /<article[^>]*>/i,
  /<div[^>]+class=["'][^"']*entry-content[^"']*["']/i,
  /<div[^>]+class=["'][^"']*post-content[^"']*["']/i,
  /<div[^>]+class=["'][^"']*td-post-content[^"']*["']/i,
  /<div[^>]+class=["'][^"']*article-body[^"']*["']/i,
  /<div[^>]+class=["'][^"']*materia-conteudo[^"']*["']/i,
  /<div[^>]+class=["'][^"']*conteudo[^"']*["']/i,
  /<div[^>]+class=["'][^"']*content[^"']*["']/i,
  /<main[^>]*>/i,
];

let conteudo = null;
for (const anchor of anchors) {
  const extracted = extractFromAnchor(html, anchor);
  if (extracted && extracted.length > 200) {
    conteudo = extracted;
    break;
  }
}

// Fallback: todos os parágrafos com texto significativo
if (!conteudo) {
  const allP = (html.match(/<p[^>]*>[\s\S]*?<\/p>/gi) || [])
    .map(p => p.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim())
    .filter(p => p.length > 60);
  if (allP.length >= 2) {
    conteudo = '<p>' + allP.slice(0, 30).join('</p>\n<p>') + '</p>';
  }
}

console.log(`📰 ${item.titulo} — conteudo: ${conteudo ? conteudo.length + ' chars' : 'não extraído'} | imagem: ${imagem_url ? 'ok' : 'null'}`);

return [{ json: { ...item, conteudo: conteudo || null, imagem_url } }];

const response = $input.item.json;
const titulo = $('🔄 Um item por vez').item.json.titulo;

if (response.success) {
  console.log(`✅ Salva: ${titulo}`);
} else if (response.skipped) {
  console.log(`⏭️ Duplicata: ${titulo}`);
} else {
  console.log(`❌ Erro: ${titulo} — ${JSON.stringify(response)}`);
}

return $input.all();
